import{_ as s}from"./plugin-vue_export-helper-DlAUqK2U.js";import{e as n,f as e,o as t}from"./app-Dr00MEJt.js";const l={};function i(p,a){return t(),n("div",null,a[0]||(a[0]=[e(`<h1 id="arpg-gas-维护与开发指南" tabindex="-1"><a class="header-anchor" href="#arpg-gas-维护与开发指南"><span>ARPG GAS 维护与开发指南</span></a></h1><p>一个长期演进的 GAS 战斗框架，<strong>真正的难点不是初次搭建，而是日常迭代</strong>。这篇整理新增技能/属性集/GE/Cue 的标准流程、调试工具、性能注意事项、常见坑、代码审查与升级 checklist。</p><h2 id="_1-新增-gameplay-ability" tabindex="-1"><a class="header-anchor" href="#_1-新增-gameplay-ability"><span>1. 新增 Gameplay Ability</span></a></h2><h3 id="_1-1-完整流程" tabindex="-1"><a class="header-anchor" href="#_1-1-完整流程"><span>1.1 完整流程</span></a></h3><h4 id="step-1-注册-gameplaytag" tabindex="-1"><a class="header-anchor" href="#step-1-注册-gameplaytag"><span>Step 1：注册 GameplayTag</span></a></h4><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre><code><span class="line"><span class="token comment"># DefaultGameplayTags.ini</span></span>
<span class="line"><span class="token key attr-name">+GameplayTagList</span><span class="token punctuation">=</span><span class="token value attr-value">(Tag=&quot;AbilityTagCategory.Action.Katana.NewSkill&quot;,DevComment=&quot;刀新技能&quot;)</span></span>
<span class="line"><span class="token key attr-name">+GameplayTagList</span><span class="token punctuation">=</span><span class="token value attr-value">(Tag=&quot;InputTag.Weapon.Katana.NewSkillInput&quot;,DevComment=&quot;刀新技能输入&quot;)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># SpellRingFlightTags.ini</span></span>
<span class="line"><span class="token key attr-name">+GameplayTagList</span><span class="token punctuation">=</span><span class="token value attr-value">(Tag=&quot;SpellRing.Katana.New.NewSkill.1&quot;,DevComment=&quot;刀新技能近战环1&quot;)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment"># GameplayCueTags.ini</span></span>
<span class="line"><span class="token key attr-name">+GameplayTagList</span><span class="token punctuation">=</span><span class="token value attr-value">(Tag=&quot;GameplayCue.Katana.NewSkill.Strike&quot;,DevComment=&quot;刀新技能命中特效&quot;)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="step-2-spellasset" tabindex="-1"><a class="header-anchor" href="#step-2-spellasset"><span>Step 2：SpellAsset</span></a></h4><ul><li>路径：<code>Content/&lt;root&gt;/Spell/Katana/</code></li><li>名称：<code>DA_Katana_NewSkill_Spell</code></li><li>基类：<code>USpellAsset</code>（近战用 <code>USpellAssetMelee</code>）</li><li>填写：蒙太奇引用、<code>StartGameplayCues</code>、<code>HitGameplayCues</code>、<code>CostStaminaPercent</code></li></ul><h4 id="step-3-spellringasset-spellflightasset" tabindex="-1"><a class="header-anchor" href="#step-3-spellringasset-spellflightasset"><span>Step 3：SpellRingAsset / SpellFlightAsset</span></a></h4><p><strong>近战：</strong></p><ul><li>路径：<code>Content/&lt;root&gt;/SpellRing/Katana/</code></li><li>名称：<code>DA_Katana_NewSkill_Ring</code></li><li>配置：Socket 名称、碰撞半径、<code>TargetEffectClass</code>（指向下一步 GE）</li></ul><p><strong>远程：</strong></p><ul><li>路径：<code>Content/&lt;root&gt;/SpellFlight/Katana/</code></li><li>名称：<code>DA_Katana_NewSkill_Flight</code></li></ul><h4 id="step-4-gameplayeffect" tabindex="-1"><a class="header-anchor" href="#step-4-gameplayeffect"><span>Step 4：GameplayEffect</span></a></h4><ul><li>路径：<code>Content/&lt;root&gt;/GE/Damage/</code></li><li>名称：<code>GE_Katana_NewSkill_Damage</code></li><li>配置： <ul><li>Duration Policy = <code>Instant</code></li><li>Modifier 目标：<code>AttributeSetBase.MetaDelta</code>，Op = <code>Add</code>，幅度用 <code>SetByCaller</code></li><li>SetByCaller Tag：<code>Damage.Physical</code></li></ul></li></ul><h4 id="step-5-blueprint-ability" tabindex="-1"><a class="header-anchor" href="#step-5-blueprint-ability"><span>Step 5：Blueprint Ability</span></a></h4><ol><li>在 <code>Content/&lt;root&gt;/Abilities/Player/Katana/</code> 新建蓝图，父类选 <code>GameplayAbilityProject</code></li><li>Class Defaults： <ul><li><code>AbilityTags</code>：加 <code>AbilityTagCategory.Action.Katana.NewSkill</code></li><li><code>ActivationBlockedTags</code>：加 <code>OwnedTagsCategory.SpecState.Dead</code></li><li><code>ActivationPolicy</code>：<code>OnInputTriggered</code></li><li><code>ActivationGroup</code>：<code>Independent</code> / <code>Exclusive_Replaceable</code></li></ul></li><li>EventGraph：<div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">Event ActivateAbility</span>
<span class="line">  → LoadSpellAsset</span>
<span class="line">  → PlayMontageAndWait</span>
<span class="line">  → On Montage End → EndAbility</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li></ol><h4 id="step-6-注册到-abilityset" tabindex="-1"><a class="header-anchor" href="#step-6-注册到-abilityset"><span>Step 6：注册到 AbilitySet</span></a></h4><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">AbilityClass: BP_GA_Katana_NewSkill</span>
<span class="line">AbilityLevel: 1</span>
<span class="line">InputTag: InputTag.Weapon.Katana.NewSkillInput</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="step-7-绑定-enhanced-input" tabindex="-1"><a class="header-anchor" href="#step-7-绑定-enhanced-input"><span>Step 7：绑定 Enhanced Input</span></a></h4><p>在 <code>Content/&lt;root&gt;/Input/</code> 相关 <code>InputMappingContext</code> 中，把新 InputTag 绑定到对应按键。</p><h3 id="_1-2-npc-boss-技能附加" tabindex="-1"><a class="header-anchor" href="#_1-2-npc-boss-技能附加"><span>1.2 NPC/Boss 技能附加</span></a></h3><ol><li>使用 <code>USpellAssetEnemy</code>，填写 <code>AlertRadius</code>、<code>CombatPhaseTag</code></li><li>在 AI BehaviorTree 中调用 <code>ActivateAbilityByTag(...)</code></li><li>AbilitySet 中已注册，<code>ActivationPolicy</code> 设为 <code>OnSpawn</code>（被动）或 <code>OnInputTriggered</code>（AI 驱动）</li></ol><h2 id="_2-新增-attributeset" tabindex="-1"><a class="header-anchor" href="#_2-新增-attributeset"><span>2. 新增 AttributeSet</span></a></h2><blockquote><p><strong>禁止手写属性集代码！</strong> 必须使用项目的代码生成工具（如 <code>AttributeSetGenerator</code>）。</p></blockquote><h3 id="_2-1-json-定义" tabindex="-1"><a class="header-anchor" href="#_2-1-json-定义"><span>2.1 JSON 定义</span></a></h3><div class="language-json line-numbers-mode" data-highlighter="prismjs" data-ext="json"><pre><code><span class="line"><span class="token punctuation">{</span></span>
<span class="line">  <span class="token property">&quot;SetName&quot;</span><span class="token operator">:</span> <span class="token string">&quot;AS_NewResource&quot;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;TagPrefix&quot;</span><span class="token operator">:</span> <span class="token string">&quot;Attribute.NewResourceSet&quot;</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;Attributes&quot;</span><span class="token operator">:</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;Name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;NewResource&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;Type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;float&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;DefaultValue&quot;</span><span class="token operator">:</span> <span class="token number">100.0</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;MinValue&quot;</span><span class="token operator">:</span> <span class="token number">0.0</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;MaxValue&quot;</span><span class="token operator">:</span> <span class="token string">&quot;MaxNewResource&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;Name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;MaxNewResource&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;Type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;float&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;DefaultValue&quot;</span><span class="token operator">:</span> <span class="token number">100.0</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">      <span class="token property">&quot;Name&quot;</span><span class="token operator">:</span> <span class="token string">&quot;RegenValue&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;Type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;float&quot;</span><span class="token punctuation">,</span></span>
<span class="line">      <span class="token property">&quot;DefaultValue&quot;</span><span class="token operator">:</span> <span class="token number">5.0</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">  <span class="token punctuation">]</span><span class="token punctuation">,</span></span>
<span class="line">  <span class="token property">&quot;IncludeMetaDelta&quot;</span><span class="token operator">:</span> <span class="token boolean">true</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>&quot;IncludeMetaDelta&quot;: true</code> 确保生成的属性集包含 <code>MetaDelta</code> 元属性。</p><h3 id="_2-2-运行代码生成" tabindex="-1"><a class="header-anchor" href="#_2-2-运行代码生成"><span>2.2 运行代码生成</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line">AttributeSetGenerator <span class="token parameter variable">--config</span> AS_NewResource.json <span class="token parameter variable">--output</span> Source/<span class="token operator">&lt;</span>Game<span class="token operator">&gt;</span>/GAS/Attributes/</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>生成 <code>AS_NewResource.h/.cpp</code>。</p><h3 id="_2-3-注册属性标签" tabindex="-1"><a class="header-anchor" href="#_2-3-注册属性标签"><span>2.3 注册属性标签</span></a></h3><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre><code><span class="line"><span class="token key attr-name">+GameplayTagList</span><span class="token punctuation">=</span><span class="token value attr-value">(Tag=&quot;Attribute.NewResourceSet.NewResource&quot;,DevComment=&quot;&quot;)</span></span>
<span class="line"><span class="token key attr-name">+GameplayTagList</span><span class="token punctuation">=</span><span class="token value attr-value">(Tag=&quot;Attribute.NewResourceSet.MaxNewResource&quot;,DevComment=&quot;&quot;)</span></span>
<span class="line"><span class="token key attr-name">+GameplayTagList</span><span class="token punctuation">=</span><span class="token value attr-value">(Tag=&quot;Attribute.NewResourceSet.MetaDelta&quot;,DevComment=&quot;&quot;)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-4-注册到-abilityset" tabindex="-1"><a class="header-anchor" href="#_2-4-注册到-abilityset"><span>2.4 注册到 AbilitySet</span></a></h3><p>在 <code>GrantedAttributes</code> 数组添加：</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">AttributeSetClass: AS_NewResource</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="_2-5-实现规范" tabindex="-1"><a class="header-anchor" href="#_2-5-实现规范"><span>2.5 实现规范</span></a></h3><p>模板会生成 <code>PostGameplayEffectExecute</code>，确认 MetaDelta 应用与归零：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token keyword">void</span> <span class="token class-name">UAS_NewResource</span><span class="token double-colon punctuation">::</span><span class="token function">PostGameplayEffectExecute</span><span class="token punctuation">(</span><span class="token keyword">const</span> FGameplayEffectModCallbackData<span class="token operator">&amp;</span> Data<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">Super</span><span class="token double-colon punctuation">::</span><span class="token function">PostGameplayEffectExecute</span><span class="token punctuation">(</span>Data<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span>Data<span class="token punctuation">.</span>EvaluatedData<span class="token punctuation">.</span>Attribute <span class="token operator">==</span> <span class="token function">GetMetaDeltaAttribute</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">const</span> <span class="token keyword">float</span> Delta <span class="token operator">=</span> <span class="token function">GetMetaDelta</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token function">SetNewResource</span><span class="token punctuation">(</span><span class="token class-name">FMath</span><span class="token double-colon punctuation">::</span><span class="token function">Clamp</span><span class="token punctuation">(</span><span class="token function">GetNewResource</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">+</span> Delta<span class="token punctuation">,</span> <span class="token number">0.f</span><span class="token punctuation">,</span> <span class="token function">GetMaxNewResource</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token function">SetMetaDelta</span><span class="token punctuation">(</span><span class="token number">0.f</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 必须！</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_3-新增-gameplayeffect" tabindex="-1"><a class="header-anchor" href="#_3-新增-gameplayeffect"><span>3. 新增 GameplayEffect</span></a></h2><h3 id="伤害-ge-标准模板" tabindex="-1"><a class="header-anchor" href="#伤害-ge-标准模板"><span>伤害 GE 标准模板</span></a></h3><table><thead><tr><th>字段</th><th>配置</th></tr></thead><tbody><tr><td>Duration Policy</td><td>Instant</td></tr><tr><td>Modifier Attribute</td><td><code>AttributeSetBase.MetaDelta</code></td></tr><tr><td>Modifier Operation</td><td>Add</td></tr><tr><td>Magnitude Calculation</td><td>SetByCaller</td></tr><tr><td>SetByCaller Tag</td><td>按伤害类型选</td></tr><tr><td>Asset Tags</td><td><code>GameplayEffect.Damage.&lt;Type&gt;</code></td></tr></tbody></table><h3 id="buff-ge-标准模板" tabindex="-1"><a class="header-anchor" href="#buff-ge-标准模板"><span>Buff GE 标准模板</span></a></h3><table><thead><tr><th>字段</th><th>配置</th></tr></thead><tbody><tr><td>Duration Policy</td><td>HasDuration / Infinite</td></tr><tr><td>Modifier Attribute</td><td>目标属性（非 MetaDelta，直接修改最终值）</td></tr><tr><td>Applied Tags</td><td><code>OwnedTagsCategory.BuffState.&lt;BuffName&gt;</code></td></tr><tr><td><code>bExecutePeriodicEffectOnApplication</code></td><td>Infinite 建议 true</td></tr></tbody></table><h3 id="周期回复-ge" tabindex="-1"><a class="header-anchor" href="#周期回复-ge"><span>周期回复 GE</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">Duration Policy: Infinite</span>
<span class="line">Period: 1.0 秒</span>
<span class="line">Modifier: AS_NewResource.MetaDelta → Add → SetByCaller(NewResource.RegenAmount)</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_4-新增-gameplaycue" tabindex="-1"><a class="header-anchor" href="#_4-新增-gameplaycue"><span>4. 新增 GameplayCue</span></a></h2><h3 id="类型选择" tabindex="-1"><a class="header-anchor" href="#类型选择"><span>类型选择</span></a></h3><table><thead><tr><th>需求</th><th>推荐类</th><th>说明</th></tr></thead><tbody><tr><td>命中特效（一次性）</td><td><code>UGameplayCueNotify_Static</code></td><td>最高效，无 Actor</td></tr><tr><td>需要时序的一次性特效</td><td><code>AGameplayCueNotify_Actor</code>（Burst）</td><td>支持延迟/序列</td></tr><tr><td>持续特效（粒子/音效循环）</td><td><code>AGameplayCueNotify_Actor</code>（Looping）</td><td>手动管理 Add/Remove</td></tr></tbody></table><h3 id="创建流程" tabindex="-1"><a class="header-anchor" href="#创建流程"><span>创建流程</span></a></h3><ol><li>注册标签：<div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre><code><span class="line"><span class="token key attr-name">+GameplayTagList</span><span class="token punctuation">=</span><span class="token value attr-value">(Tag=&quot;GameplayCue.Katana.NewSkill.Strike&quot;,DevComment=&quot;&quot;)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div></li><li>在 <code>Content/&lt;root&gt;/GameplayCue/</code> 下创建 GCN 蓝图子类</li><li>实现蓝图事件（以 Static 为例）：<div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">On Execute (Static)</span>
<span class="line">  → Get Target Actor from Params</span>
<span class="line">  → Spawn Niagara System At Location</span>
<span class="line">  → Play Wwise Event</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></li><li>在 SpellProductAsset 的 <code>GameplayCues</code> 字段添加该标签</li></ol><blockquote><p><strong>关键</strong>：GameplayCue 标签必须以 <code>GameplayCue.</code> 开头，引擎才能正确路由。</p></blockquote><h2 id="_5-新增-executioncalculation" tabindex="-1"><a class="header-anchor" href="#_5-新增-executioncalculation"><span>5. 新增 ExecutionCalculation</span></a></h2><h3 id="_5-1-用途" tabindex="-1"><a class="header-anchor" href="#_5-1-用途"><span>5.1 用途</span></a></h3><p>伤害计算不是简单加法/乘法，需要访问攻击方和防御方多个属性做复杂计算时，用 <code>UGameplayEffectExecutionCalculation</code>。</p><h3 id="_5-2-c-框架" tabindex="-1"><a class="header-anchor" href="#_5-2-c-框架"><span>5.2 C++ 框架</span></a></h3><p>头文件：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">pragma</span> <span class="token expression">once</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;CoreMinimal.h&quot;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;GameplayEffectExecutionCalculation.h&quot;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;GEC_NewDamageCalc.generated.h&quot;</span></span></span>
<span class="line"></span>
<span class="line"><span class="token function">UCLASS</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">class</span> <span class="token class-name">GAME_API</span> UGEC_NewDamageCalc <span class="token operator">:</span> <span class="token keyword">public</span> UGameplayEffectExecutionCalculation</span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">GENERATED_BODY</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">public</span><span class="token operator">:</span></span>
<span class="line">    <span class="token function">UGEC_NewDamageCalc</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">virtual</span> <span class="token keyword">void</span> <span class="token function">Execute_Implementation</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token keyword">const</span> FGameplayEffectCustomExecutionParameters<span class="token operator">&amp;</span> ExecutionParams<span class="token punctuation">,</span></span>
<span class="line">        FGameplayEffectCustomExecutionOutput<span class="token operator">&amp;</span> OutExecutionOutput<span class="token punctuation">)</span> <span class="token keyword">const</span> <span class="token keyword">override</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>实现：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;GEC_NewDamageCalc.h&quot;</span></span></span>
<span class="line"><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&quot;GAS/Attributes/AS_Health.h&quot;</span></span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 声明要从源/目标捕获的属性</span></span>
<span class="line"><span class="token keyword">struct</span> <span class="token class-name">FNewDamageStatics</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">DECLARE_ATTRIBUTE_CAPTUREDEF</span><span class="token punctuation">(</span>MetaDelta<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token function">FNewDamageStatics</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token function">DEFINE_ATTRIBUTE_CAPTUREDEF</span><span class="token punctuation">(</span>UAS_Health<span class="token punctuation">,</span> MetaDelta<span class="token punctuation">,</span> Target<span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">static</span> <span class="token keyword">const</span> FNewDamageStatics<span class="token operator">&amp;</span> <span class="token function">GetNewDamageStatics</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">static</span> FNewDamageStatics Statics<span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">return</span> Statics<span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token class-name">UGEC_NewDamageCalc</span><span class="token double-colon punctuation">::</span><span class="token function">UGEC_NewDamageCalc</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    RelevantAttributesToCapture<span class="token punctuation">.</span><span class="token function">Add</span><span class="token punctuation">(</span><span class="token function">GetNewDamageStatics</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>MetaDeltaDef<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">void</span> <span class="token class-name">UGEC_NewDamageCalc</span><span class="token double-colon punctuation">::</span><span class="token function">Execute_Implementation</span><span class="token punctuation">(</span></span>
<span class="line">    <span class="token keyword">const</span> FGameplayEffectCustomExecutionParameters<span class="token operator">&amp;</span> ExecutionParams<span class="token punctuation">,</span></span>
<span class="line">    FGameplayEffectCustomExecutionOutput<span class="token operator">&amp;</span> OutExecutionOutput<span class="token punctuation">)</span> <span class="token keyword">const</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 1. 取 SetByCaller 基础伤害</span></span>
<span class="line">    <span class="token keyword">const</span> <span class="token keyword">float</span> BaseDamage <span class="token operator">=</span> ExecutionParams<span class="token punctuation">.</span><span class="token function">GetOwningSpec</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">GetSetByCallerMagnitude</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token class-name">FGameplayTag</span><span class="token double-colon punctuation">::</span><span class="token function">RequestGameplayTag</span><span class="token punctuation">(</span><span class="token function">TEXT</span><span class="token punctuation">(</span><span class="token string">&quot;Damage.Physical&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">,</span> <span class="token number">0.f</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 2. 自定义计算（捕获属性、查询标签、缩放公式）</span></span>
<span class="line">    <span class="token keyword">const</span> <span class="token keyword">float</span> FinalDamage <span class="token operator">=</span> BaseDamage<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 3. 输出到目标 MetaDelta（负值 = 减少）</span></span>
<span class="line">    OutExecutionOutput<span class="token punctuation">.</span><span class="token function">AddOutputModifier</span><span class="token punctuation">(</span></span>
<span class="line">        <span class="token function">FGameplayModifierEvaluatedData</span><span class="token punctuation">(</span></span>
<span class="line">            <span class="token function">GetNewDamageStatics</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span>MetaDeltaDef<span class="token punctuation">.</span>AttributeToCapture<span class="token punctuation">,</span></span>
<span class="line">            EGameplayModOp<span class="token double-colon punctuation">::</span>Additive<span class="token punctuation">,</span></span>
<span class="line">            <span class="token operator">-</span>FinalDamage<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_5-3-在-ge-中使用" tabindex="-1"><a class="header-anchor" href="#_5-3-在-ge-中使用"><span>5.3 在 GE 中使用</span></a></h3><p>在 GE 的 <code>Execution Calculations</code> 数组添加 <code>UGEC_NewDamageCalc</code>，移除普通 Modifier。</p><h2 id="_6-调试工具与日志" tabindex="-1"><a class="header-anchor" href="#_6-调试工具与日志"><span>6. 调试工具与日志</span></a></h2><h3 id="_6-1-控制台命令" tabindex="-1"><a class="header-anchor" href="#_6-1-控制台命令"><span>6.1 控制台命令</span></a></h3><div class="language-bash line-numbers-mode" data-highlighter="prismjs" data-ext="sh"><pre><code><span class="line"><span class="token comment"># 角色身上所有激活的 GAS 信息</span></span>
<span class="line">showdebug abilitysystem</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 切换调试目标</span></span>
<span class="line">AbilitySystem.Debug.NextTarget</span>
<span class="line">AbilitySystem.Debug.PrevTarget</span>
<span class="line"></span>
<span class="line"><span class="token comment"># 日志开关</span></span>
<span class="line">log LogAbilitySystem verbose         <span class="token comment"># GameplayTag 变化</span></span>
<span class="line">log LogProjectAbilitySystem verbose  <span class="token comment"># 项目层能力激活</span></span>
<span class="line">log LogProjectSpell verbose          <span class="token comment"># 施法/Ring/Flight</span></span>
<span class="line">log LogFrameworkAbilitySystem verbose <span class="token comment"># 框架层</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-2-showdebug-面板示例" tabindex="-1"><a class="header-anchor" href="#_6-2-showdebug-面板示例"><span>6.2 showdebug 面板示例</span></a></h3><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code><span class="line">[Ability System Component Debug]</span>
<span class="line">  Owner: BP_GameCharacter_0 (Player)</span>
<span class="line"></span>
<span class="line">  --- ATTRIBUTES ---</span>
<span class="line">  Health: 350/500        StaminaSet.Stamina: 80/100</span>
<span class="line">  BreakSet.Break: 120/200</span>
<span class="line"></span>
<span class="line">  --- ACTIVE EFFECTS ---</span>
<span class="line">  [INFINITE] GE_Passive_StaminaRegen (Level 1)</span>
<span class="line">  [10.2s] GE_DefenseUp_10s (Level 1)</span>
<span class="line"></span>
<span class="line">  --- ACTIVE ABILITIES ---</span>
<span class="line">  [ACTIVE] BP_GA_Katana_Light.01 (Group: Independent)</span>
<span class="line"></span>
<span class="line">  --- BLOCKED ABILITIES ---</span>
<span class="line">  BP_GA_Katana_Heavy (Blocked by: Active group)</span>
<span class="line"></span>
<span class="line">  --- OWNED TAGS ---</span>
<span class="line">  OwnedTagsCategory.State.InCombat</span>
<span class="line">  AbilityTagCategory.Action.Katana.Light.01</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-3-属性变化日志" tabindex="-1"><a class="header-anchor" href="#_6-3-属性变化日志"><span>6.3 属性变化日志</span></a></h3><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token class-name">UAbilitySystemGlobals</span><span class="token double-colon punctuation">::</span><span class="token function">Get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">ShouldLogAbilitySystemAnalytics</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">OnGameplayAttributeValueChange</span><span class="token punctuation">(</span><span class="token generic-function"><span class="token function">GetAttributeSet</span><span class="token generic class-name"><span class="token operator">&lt;</span>UAS_Health<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token function">GetHealthAttribute</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">AddLambda</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token keyword">const</span> FOnAttributeChangeData<span class="token operator">&amp;</span> Data<span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            <span class="token function">UE_LOG</span><span class="token punctuation">(</span>LogProjectAbilitySystem<span class="token punctuation">,</span> Log<span class="token punctuation">,</span> <span class="token function">TEXT</span><span class="token punctuation">(</span><span class="token string">&quot;Health changed: %.1f → %.1f&quot;</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">                Data<span class="token punctuation">.</span>OldValue<span class="token punctuation">,</span> Data<span class="token punctuation">.</span>NewValue<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_6-4-spellring-可视化" tabindex="-1"><a class="header-anchor" href="#_6-4-spellring-可视化"><span>6.4 SpellRing 可视化</span></a></h3><p>蓝图中的 Ring 资产可设置 <code>bDebugTrace = true</code>，在场景中显示碰撞球体轮廓。</p><h3 id="_6-5-常用调试函数" tabindex="-1"><a class="header-anchor" href="#_6-5-常用调试函数"><span>6.5 常用调试函数</span></a></h3><table><thead><tr><th>函数</th><th>用途</th></tr></thead><tbody><tr><td><code>GetActiveGameplayEffectsDebugString</code></td><td>所有激活 GE 的可读字符串</td></tr><tr><td><code>GetGrantedAbilitiesDebugString</code></td><td>所有已授权能力的调试信息</td></tr><tr><td><code>PrintAllOwnedTags</code></td><td>打印当前所有 OwnedTag</td></tr><tr><td><code>GetAttributeValueByTag</code></td><td>通过标签获取属性当前值</td></tr></tbody></table><h2 id="_7-性能注意事项" tabindex="-1"><a class="header-anchor" href="#_7-性能注意事项"><span>7. 性能注意事项</span></a></h2><h3 id="_7-1-属性集" tabindex="-1"><a class="header-anchor" href="#_7-1-属性集"><span>7.1 属性集</span></a></h3><ul><li>单个属性集建议不超过 20 个属性</li><li>每个属性集只有一个 MetaDelta，所有伤害/回复都走这一入口</li><li>回复型 GE 使用 Period，不要在 Tick 中直接修改属性</li></ul><h3 id="_7-2-ge-应用频率" tabindex="-1"><a class="header-anchor" href="#_7-2-ge-应用频率"><span>7.2 GE 应用频率</span></a></h3><table><thead><tr><th>类型</th><th>限制建议</th></tr></thead><tbody><tr><td>Instant GE</td><td>无限制，但确保 ExecutionCalc 无复杂查询</td></tr><tr><td>HasDuration GE</td><td>不要在同一帧应用超过 10 个</td></tr><tr><td>周期 GE（Period &lt; 0.1s）</td><td>禁止，最小 Period 为 0.1 秒</td></tr><tr><td>Infinite GE</td><td>生命周期明确，确保 RemoveGameplayEffect 被调用</td></tr></tbody></table><h3 id="_7-3-技能激活开销" tabindex="-1"><a class="header-anchor" href="#_7-3-技能激活开销"><span>7.3 技能激活开销</span></a></h3><ul><li><code>CanActivateAbility</code> 中避免 Line Trace 或大量标签迭代</li><li>近战技能默认 <code>InstancedPerActor</code>，避免 <code>InstancedPerExecution</code> 的对象分配</li><li>Ring 和 Flight 任务通过对象池管理，不要 <code>SpawnActor</code></li></ul><h3 id="_7-4-对象池使用" tabindex="-1"><a class="header-anchor" href="#_7-4-对象池使用"><span>7.4 对象池使用</span></a></h3><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// 正确 — 通过 GameMode 对象池</span></span>
<span class="line">AGameMode<span class="token operator">*</span> GameMode <span class="token operator">=</span> <span class="token generic-function"><span class="token function">Cast</span><span class="token generic class-name"><span class="token operator">&lt;</span>AGameMode<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token function">GetWorld</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token function">GetAuthGameMode</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token keyword">if</span> <span class="token punctuation">(</span>GameMode<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    ASpellFlight<span class="token operator">*</span> Flight <span class="token operator">=</span> GameMode<span class="token operator">-&gt;</span><span class="token function">AllocSpellFlight</span><span class="token punctuation">(</span>FlightTag<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 错误 — 直接 SpawnActor</span></span>
<span class="line">ASpellFlight<span class="token operator">*</span> Flight <span class="token operator">=</span> <span class="token function">GetWorld</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token operator">-&gt;</span><span class="token generic-function"><span class="token function">SpawnActor</span><span class="token generic class-name"><span class="token operator">&lt;</span>ASpellFlight<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 禁止</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_7-5-标签查询" tabindex="-1"><a class="header-anchor" href="#_7-5-标签查询"><span>7.5 标签查询</span></a></h3><ul><li>热路径（命中检测/Tick）：使用 <code>UAbilitySystemGlobalsProject::Get().DeadTag</code> 等缓存标签</li><li>冷路径（技能激活初始化）：允许使用 <code>FGameplayTag::RequestGameplayTag()</code></li><li>容器查询：使用 <code>HasTagExact()</code> 精确匹配，避免不必要的子标签匹配开销</li></ul><h3 id="_7-6-资产异步加载" tabindex="-1"><a class="header-anchor" href="#_7-6-资产异步加载"><span>7.6 资产异步加载</span></a></h3><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token comment">// 正确 — 异步</span></span>
<span class="line"><span class="token class-name">AssetManager</span><span class="token double-colon punctuation">::</span><span class="token function">Get</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">RequestAsyncLoad</span><span class="token punctuation">(</span></span>
<span class="line">    SpellAssetPath<span class="token punctuation">,</span></span>
<span class="line">    <span class="token class-name">FStreamableDelegate</span><span class="token double-colon punctuation">::</span><span class="token function">CreateWeakLambda</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token keyword">this</span><span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> <span class="token comment">/* ... */</span> <span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 错误 — 同步加载，游戏线程阻塞</span></span>
<span class="line">USpellAsset<span class="token operator">*</span> Asset <span class="token operator">=</span> <span class="token generic-function"><span class="token function">Cast</span><span class="token generic class-name"><span class="token operator">&lt;</span>USpellAsset<span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>SpellAssetPath<span class="token punctuation">.</span><span class="token function">LoadSynchronous</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_8-常见问题排查" tabindex="-1"><a class="header-anchor" href="#_8-常见问题排查"><span>8. 常见问题排查</span></a></h2><h3 id="_8-1-技能无法激活" tabindex="-1"><a class="header-anchor" href="#_8-1-技能无法激活"><span>8.1 技能无法激活</span></a></h3><p><strong>症状</strong>：调用 <code>ActivateAbilityByTag</code> 后无响应。</p><p><strong>检查</strong>：</p><ol><li>角色 ASC 是否通过 <code>AbilitySet.GiveToAbilitySystem()</code> 授权了该技能</li><li><code>ActivationBlockedTags</code> 是否包含当前角色持有的标签</li><li><code>CheckCost</code> 是否返回 true（耐力/弹药是否足够）</li><li><code>ActivationGroup</code> 是否冲突（当前是否有 <code>Exclusive_Blocking</code> 技能在执行）</li><li>开 <code>log LogProjectAbilitySystem verbose</code> 看具体失败原因</li></ol><h3 id="_8-2-伤害未应用" tabindex="-1"><a class="header-anchor" href="#_8-2-伤害未应用"><span>8.2 伤害未应用</span></a></h3><p><strong>症状</strong>：Ring/Flight 命中目标，但对方生命值不变。</p><p><strong>检查</strong>：</p><ol><li>SpellRing/SpellFlight 的 <code>TargetEffectClass</code> 是否设置</li><li>GE 的 Modifier 目标属性是否为 <code>MetaDelta</code>（不是 <code>Health</code>）</li><li>SetByCaller 标签是否在 GE 中声明，且在 SpellProductAsset 中有值</li><li>目标角色是否拥有对应属性集</li><li><code>FFightTargetFilter</code> 的 <code>bCanHitFriendly</code> / <code>bCanHitNeutral</code> 是否正确</li></ol><h3 id="_8-3-metadelta-未清零" tabindex="-1"><a class="header-anchor" href="#_8-3-metadelta-未清零"><span>8.3 MetaDelta 未清零</span></a></h3><p><strong>症状</strong>：属性值持续减少，远超预期。</p><p><strong>修复</strong>：</p><div class="language-cpp line-numbers-mode" data-highlighter="prismjs" data-ext="cpp"><pre><code><span class="line"><span class="token keyword">void</span> <span class="token class-name">UAS_Health</span><span class="token double-colon punctuation">::</span><span class="token function">PostGameplayEffectExecute</span><span class="token punctuation">(</span><span class="token keyword">const</span> FGameplayEffectModCallbackData<span class="token operator">&amp;</span> Data<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">Super</span><span class="token double-colon punctuation">::</span><span class="token function">PostGameplayEffectExecute</span><span class="token punctuation">(</span>Data<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">if</span> <span class="token punctuation">(</span>Data<span class="token punctuation">.</span>EvaluatedData<span class="token punctuation">.</span>Attribute <span class="token operator">==</span> <span class="token function">GetMetaDeltaAttribute</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token comment">// ... 应用伤害 ...</span></span>
<span class="line">        <span class="token function">SetMetaDelta</span><span class="token punctuation">(</span><span class="token number">0.f</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 必须！</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_8-4-gameplaycue-未播放" tabindex="-1"><a class="header-anchor" href="#_8-4-gameplaycue-未播放"><span>8.4 GameplayCue 未播放</span></a></h3><p><strong>检查</strong>：</p><ol><li>标签名是否以 <code>GameplayCue.</code> 开头（必须）</li><li>GCN 资产是否在 <code>DefaultGame.ini</code> 的 <code>GameplayCueNotifyPaths</code> 扫描路径下</li><li>Looping 类型是否配对了 <code>OnActive</code> 和 <code>OnRemove</code></li><li>GCN 实现的事件是否正确（Static = <code>OnExecute</code>；Actor = <code>OnActive</code>）</li></ol><h3 id="_8-5-对象池耗尽" tabindex="-1"><a class="header-anchor" href="#_8-5-对象池耗尽"><span>8.5 对象池耗尽</span></a></h3><p><strong>症状</strong>：战斗高峰期飞行物/近战环无法生成，日志出现 <code>AllocSpellFlight failed: Pool empty</code>。</p><p><strong>解决</strong>：</p><ol><li>增大对应对象池的初始容量</li><li>检查 <code>ASpellFlight::DoSink()</code> 是否在所有路径（命中/超时/被销毁）都被调用</li><li>确认飞行物 Lifetime 设置合理</li></ol><h2 id="_9-代码审查-checklist" tabindex="-1"><a class="header-anchor" href="#_9-代码审查-checklist"><span>9. 代码审查 checklist</span></a></h2><h3 id="能力-ability" tabindex="-1"><a class="header-anchor" href="#能力-ability"><span>能力（Ability）</span></a></h3><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-0" disabled="disabled"><label class="task-list-item-label" for="task-item-0"> 继承自项目能力基类（而非直接框架基类）</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-1" disabled="disabled"><label class="task-list-item-label" for="task-item-1"><code>AbilityTags</code> 至少包含一个 <code>AbilityTagCategory.*</code> 标签</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-2" disabled="disabled"><label class="task-list-item-label" for="task-item-2"><code>ActivationBlockedTags</code> 包含 <code>OwnedTagsCategory.SpecState.Dead</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-3" disabled="disabled"><label class="task-list-item-label" for="task-item-3"><code>EndAbility()</code> 在所有执行路径（正常/被打断/超时）均有调用</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-4" disabled="disabled"><label class="task-list-item-label" for="task-item-4"> AbilityTask 通过 <code>ReadyForActivation()</code> 正确启动</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-5" disabled="disabled"><label class="task-list-item-label" for="task-item-5"> SpellAsset 使用软引用 + 异步加载，不使用同步加载</label></li></ul><h3 id="属性集" tabindex="-1"><a class="header-anchor" href="#属性集"><span>属性集</span></a></h3><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-6" disabled="disabled"><label class="task-list-item-label" for="task-item-6"> 由代码生成工具产出，未手动编写</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-7" disabled="disabled"><label class="task-list-item-label" for="task-item-7"> 包含 <code>MetaDelta</code> 元属性</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-8" disabled="disabled"><label class="task-list-item-label" for="task-item-8"><code>PostGameplayEffectExecute</code> 中 MetaDelta 在使用后归零</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-9" disabled="disabled"><label class="task-list-item-label" for="task-item-9"><code>PreAttributeChange</code> 中对 Max 属性变化有 <code>AdjustAttributeForMaxChange</code> 调用</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-10" disabled="disabled"><label class="task-list-item-label" for="task-item-10"> 已在 <code>DefaultGameplayTags.ini</code> 注册对应属性标签</label></li></ul><h3 id="gameplayeffect" tabindex="-1"><a class="header-anchor" href="#gameplayeffect"><span>GameplayEffect</span></a></h3><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-11" disabled="disabled"><label class="task-list-item-label" for="task-item-11"> 伤害 GE 的 Modifier 目标为 <code>MetaDelta</code>，不是最终属性</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-12" disabled="disabled"><label class="task-list-item-label" for="task-item-12"> SetByCaller 标签已在标签 ini 中定义</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-13" disabled="disabled"><label class="task-list-item-label" for="task-item-13"> GE 的 <code>Asset Tags</code> 已正确分类</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-14" disabled="disabled"><label class="task-list-item-label" for="task-item-14"> Duration GE 的 Applied Tags 有对应的 UI 显示处理</label></li></ul><h3 id="近战环-飞行物" tabindex="-1"><a class="header-anchor" href="#近战环-飞行物"><span>近战环 / 飞行物</span></a></h3><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-15" disabled="disabled"><label class="task-list-item-label" for="task-item-15"> 通过对象池分配，不使用 <code>SpawnActor</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-16" disabled="disabled"><label class="task-list-item-label" for="task-item-16"><code>DoSink()</code> 在所有结束路径调用</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-17" disabled="disabled"><label class="task-list-item-label" for="task-item-17"> SpellRing/Flight 资产的标签已在 <code>SpellRingFlightTags.ini</code> 注册</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-18" disabled="disabled"><label class="task-list-item-label" for="task-item-18"><code>OneTimeTargetingPreset</code>（爆炸范围等）已在 TargetingSystem 文档中记录</label></li></ul><h3 id="代码规范" tabindex="-1"><a class="header-anchor" href="#代码规范"><span>代码规范</span></a></h3><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-19" disabled="disabled"><label class="task-list-item-label" for="task-item-19"> 注释使用英文</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-20" disabled="disabled"><label class="task-list-item-label" for="task-item-20"> 使用 <code>TObjectPtr&lt;&gt;</code> 代替裸 <code>UObject*</code></label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-21" disabled="disabled"><label class="task-list-item-label" for="task-item-21"> Lambda 使用 <code>CreateWeakLambda</code>，避免裸 <code>[&amp;]</code> 或 <code>[=]</code> 捕获</label></li></ul><h2 id="_10-升级-checklist" tabindex="-1"><a class="header-anchor" href="#_10-升级-checklist"><span>10. 升级 checklist</span></a></h2><h3 id="引擎版本升级" tabindex="-1"><a class="header-anchor" href="#引擎版本升级"><span>引擎版本升级</span></a></h3><ol><li><strong>属性集重新生成</strong>：用代码生成工具重跑，对比生成前后的差异</li><li><strong>核心 GAS 接口验证</strong>： <ul><li><code>UAbilitySystemComponent::InitAbilityActorInfo</code> 签名</li><li><code>FGameplayEffectSpec</code> 构造参数</li><li><code>UGameplayAbility::ActivateAbility</code> 参数顺序</li><li><code>FGameplayEffectCustomExecutionParameters::GetOwningSpec()</code></li></ul></li><li><strong>框架层兼容性</strong>：检查所有内部框架基类是否与新引擎 API 兼容</li><li><strong>Experimental 插件</strong>：<code>GameplayTargetingSystem</code> 是否毕业为正式功能、<code>UTargetingSubsystem</code> 接口变化</li><li><strong>冒烟测试</strong>： <ul><li>玩家基础连招命中敌人扣血</li><li>射击飞行物正确生成、命中、回收</li><li>大招激活，阻止其他技能激活</li><li>死亡后所有 Infinite GE 被移除</li><li>GameplayCue 特效/音效正常触发</li></ul></li></ol><h3 id="新武器类型上线前" tabindex="-1"><a class="header-anchor" href="#新武器类型上线前"><span>新武器类型上线前</span></a></h3><ul class="task-list-container"><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-22" disabled="disabled"><label class="task-list-item-label" for="task-item-22"> 武器相关 AbilityTag / InputTag / SpellTag / SpellRingTag / SpellFlightTag 全部注册</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-23" disabled="disabled"><label class="task-list-item-label" for="task-item-23"> AbilitySet DataAsset 创建并与角色绑定</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-24" disabled="disabled"><label class="task-list-item-label" for="task-item-24"> TagRelationshipMapping 已更新</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-25" disabled="disabled"><label class="task-list-item-label" for="task-item-25"> 所有 SpellProductAsset 的 <code>SetByCallerMagnitudes</code> 已填写数值</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-26" disabled="disabled"><label class="task-list-item-label" for="task-item-26"> GameplayCue 资产在扫描路径下且命名符合规范</label></li><li class="task-list-item"><input type="checkbox" class="task-list-item-checkbox" id="task-item-27" disabled="disabled"><label class="task-list-item-label" for="task-item-27"> 对象池容量已评估（如有大量新飞行物类型）</label></li></ul>`,122)]))}const d=s(l,[["render",i],["__file","arpg-gas-maintenance.html.vue"]]),u=JSON.parse('{"path":"/GameEngine/Unreal/GAS/arpg-gas-maintenance.html","title":"ARPG GAS 维护与开发指南","lang":"en-US","frontmatter":{"date":"2025-02-24T00:00:00.000Z","tag":["Unreal Engine","GAS"]},"git":{"createdTime":1782381773000,"updatedTime":1782381773000,"contributors":[{"name":"BanMing","username":"BanMing","email":"ban-ming@foxmail.com","commits":1,"url":"https://github.com/BanMing"},{"name":"Claude Opus 4.7","username":"Claude Opus 4.7","email":"noreply@anthropic.com","commits":1,"url":"https://github.com/Claude Opus 4.7"}]},"readingTime":{"minutes":8.2,"words":2461},"filePathRelative":"GameEngine/Unreal/GAS/arpg-gas-maintenance.md","localizedDate":"February 24, 2025","excerpt":"\\n<p>一个长期演进的 GAS 战斗框架，<strong>真正的难点不是初次搭建，而是日常迭代</strong>。这篇整理新增技能/属性集/GE/Cue 的标准流程、调试工具、性能注意事项、常见坑、代码审查与升级 checklist。</p>\\n<h2>1. 新增 Gameplay Ability</h2>\\n<h3>1.1 完整流程</h3>\\n<h4>Step 1：注册 GameplayTag</h4>\\n<div class=\\"language-ini line-numbers-mode\\" data-highlighter=\\"prismjs\\" data-ext=\\"ini\\"><pre><code><span class=\\"line\\"><span class=\\"token comment\\"># DefaultGameplayTags.ini</span></span>\\n<span class=\\"line\\"><span class=\\"token key attr-name\\">+GameplayTagList</span><span class=\\"token punctuation\\">=</span><span class=\\"token value attr-value\\">(Tag=\\"AbilityTagCategory.Action.Katana.NewSkill\\",DevComment=\\"刀新技能\\")</span></span>\\n<span class=\\"line\\"><span class=\\"token key attr-name\\">+GameplayTagList</span><span class=\\"token punctuation\\">=</span><span class=\\"token value attr-value\\">(Tag=\\"InputTag.Weapon.Katana.NewSkillInput\\",DevComment=\\"刀新技能输入\\")</span></span>\\n<span class=\\"line\\"></span>\\n<span class=\\"line\\"><span class=\\"token comment\\"># SpellRingFlightTags.ini</span></span>\\n<span class=\\"line\\"><span class=\\"token key attr-name\\">+GameplayTagList</span><span class=\\"token punctuation\\">=</span><span class=\\"token value attr-value\\">(Tag=\\"SpellRing.Katana.New.NewSkill.1\\",DevComment=\\"刀新技能近战环1\\")</span></span>\\n<span class=\\"line\\"></span>\\n<span class=\\"line\\"><span class=\\"token comment\\"># GameplayCueTags.ini</span></span>\\n<span class=\\"line\\"><span class=\\"token key attr-name\\">+GameplayTagList</span><span class=\\"token punctuation\\">=</span><span class=\\"token value attr-value\\">(Tag=\\"GameplayCue.Katana.NewSkill.Strike\\",DevComment=\\"刀新技能命中特效\\")</span></span>\\n<span class=\\"line\\"></span></code></pre>\\n<div class=\\"line-numbers\\" aria-hidden=\\"true\\" style=\\"counter-reset:line-number 0\\"><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div><div class=\\"line-number\\"></div></div></div>"}');export{d as comp,u as data};
